What does this program print?

```cpp
#include <iostream>

int triple(int x)
{
    return x * 3;
}

int main()
{
    std::cout << triple(4) << "\n";
    std::cout << triple(triple(2)) << "\n";
    return 0;
}
```

What does this program print?

```cpp
#include <iostream>

void printLine()
{
    std::cout << "---\n";
}

void printValue(int v)
{
    std::cout << "Val: " << v << "\n";
}

int main()
{
    printLine();
    printValue(5);
    printLine();
    return 0;
}
```

